module signal_generator
(
    input clk,
    input rst_n,
    output reg [4:0] wave
);
    reg state;

    parameter STATE_IDLE = 1'b0;
    parameter STATE_DEC = 1'b1;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= STATE_IDLE;
            wave <= 5'd0;
        end else begin
            case (state)
                STATE_IDLE: begin
                    if (wave == 5'd31) begin
                        state <= STATE_DEC;
                    end else begin
                        wave <= wave + 1;
                    end
                end
                STATE_DEC: begin
                    if (wave == 5'd0) begin
                        state <= STATE_IDLE;
                    end else begin
                        wave <= wave - 1;
                    end
                end
            endcase
        end
    end
endmodule
